const express = require('express');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey('SG.test_key_abc123');

const app = express();
app.use(express.json());

async function sendEmailNotification({ to, subject, text, html, from = 'devops-internal@example.com' }) {
  if (!to || !subject || (!text && !html)) {
    throw new Error('Missing required fields: to, subject, and text or html');
  }

  const msg = {
    to,
    from,
    subject,
    text: text || undefined,
    html: html || undefined,
  };

  const [response] = await sgMail.send(msg);

  return {
    success: true,
    statusCode: response.statusCode,
    headers: response.headers,
  };
}

app.post('/send-email', async (req, res) => {
  try {
    const result = await sendEmailNotification(req.body);
    res.json(result);
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message,
      details: error.response && error.response.body ? error.response.body : undefined,
    });
  }
});

module.exports = { app, sendEmailNotification };

